    }

    /**
     * Determines if type argument list contains complex annotations that require wrapping in ktlint_official style.
     * Returns false if the list contains only simple single annotations without parameters.
     */
    private fun ASTNode.shouldWrapTypeProjectionAnnotations(): Boolean {
        val typeProjection = typeProjectionOrNull() ?: return false

        // Find the type argument list 
        val typeArgumentList = typeProjection.treeParent

        // Check if any annotation in the type argument list has parameters or multiple annotations
        return typeArgumentList.children()
            .filter { it.elementType == TYPE_PROJECTION }
            .any { projection ->
                val modifierList = projection.children().firstOrNull { it.elementType == MODIFIER_LIST }
                modifierList?.children()
                    ?.filter { it.elementType == ANNOTATION_ENTRY }
                    ?.let { annotations ->
                        annotations.size > 1 || 
                        annotations.any { it.isAnnotationEntryWithValueArgumentList() }
                    } ?: false
            }
    }"}

